
(function(){
'use strict';
var SHARED_LOGO_URI='data:image/png;base64,';

// Desktop (>=768px)
(function(){
  var wrapEl=document.getElementById('tmd-wrap-d');
  if(!wrapEl||wrapEl.offsetParent===null) return;
  var canvas=document.getElementById('tmd-c');
  var ctx=canvas.getContext('2d');
  var ctaBtn=document.getElementById('tmd-cta-d');
  var ctaShown=false;

const NAVY="#003E52", TEAL="#006B73", TEAL_L="#007f85", ORANGE="#FF5A36";
const BG="#F4EFE8", INK="#1C1208", RED="#C8291F", CREAM="#FAF7F2";

let W=1100, H=640;
function resize() {
  const wrap = document.getElementById("tmd-wrap-d");
  const cssW = wrap.clientWidth;
  const cssH = Math.round(cssW * 0.582);
  const dpr  = Math.min(window.devicePixelRatio||1, 2);
  canvas.style.width=cssW+"px"; canvas.style.height=cssH+"px";
  canvas.width=cssW*dpr; canvas.height=cssH*dpr;
  ctx.setTransform(dpr,0,0,dpr,0,0);
  W=cssW; H=cssH;
}
resize(); window.addEventListener("resize", resize);

const logoImg = new Image();
logoImg.src=SHARED_LOGO_URI;

function easeOut(t)   { return 1-Math.pow(1-t,3); }
function easeOut2(t)  { return 1-(1-t)*(1-t); }
function spring(t)    { return 1+Math.pow(2,-9*t)*Math.sin((t-0.22)*Math.PI*2/0.55)*(-1.12); }
function lerp(a,b,t)  { return a+(b-a)*t; }
function clamp(v,a,b) { return Math.max(a,Math.min(b,v)); }
function _rr(x,y,w,h,r){
  ctx.beginPath(); ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y);
  ctx.quadraticCurveTo(x+w,y,x+w,y+r); ctx.lineTo(x+w,y+h-r);
  ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h); ctx.lineTo(x+r,y+h);
  ctx.quadraticCurveTo(x,y+h,x,y+h-r); ctx.lineTo(x,y+r);
  ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath();
}

const ITEMS = [
  { prob:"Insurance runaround",  sol:"No insurance required",    sub:"No prior auth. No denials."     },
  { prob:"Rotating providers",   sol:"Same doctor, every time",  sub:"Continuity of care, always"     },
  { prob:"Chatbot medicine",     sol:"Board-certified MD",       sub:"A real doctor. A real answer."  },
  { prob:"Long wait times",       sol:"Same-day appointments",    sub:"Book online in under 2 minutes" },
  { prob:"Outrageous bills",     sol:"$49. One price.",          sub:"One payment. Nothing hidden."   },
];

let scratchPaths=[];
function buildScratch(y,x0,x1,seed){
  const strokes=[];
  for(let s=0;s<3;s++){
    const pts=[],n=20;
    const yOff=(s-1)*3.6+Math.sin(seed*7.3+s)*1.8;
    for(let i=0;i<=n;i++){
      const t=i/n;
      const w=Math.sin(seed*13.1+i*2.9+s*5.7)*2.0+Math.cos(seed*8.4+i*4.1)*1.0;
      pts.push({x:x0+t*(x1-x0), y:y+yOff+w});
    }
    strokes.push({pts, w:s===1?3.6:2.0});
  }
  return strokes;
}

let pops=[];
function spawnPop(x,y){
  const cols=[TEAL_L,ORANGE,NAVY,"#00a89a","#FF8A6A","#005f66"];
  for(let i=0;i<8;i++){
    const ang=(Math.PI*2*i/8)+Math.random()*0.4;
    const dist=12+Math.random()*20;
    pops.push({x,y,tx:x+Math.cos(ang)*dist,ty:y+Math.sin(ang)*dist,
               r:2.2+Math.random()*3.2,alpha:1,col:cols[i%cols.length],age:0});
  }
}
function tickPops(dt){
  pops.forEach(p=>{
    p.age+=dt/750; p.x=lerp(p.x,p.tx,0.13); p.y=lerp(p.y,p.ty,0.13);
    p.alpha=Math.max(0,1-p.age*1.1); p.r*=0.977;
  });
  pops=pops.filter(p=>p.alpha>0.01);
}
function drawPops(){
  pops.forEach(p=>{
    ctx.save(); ctx.globalAlpha=p.alpha;
    ctx.fillStyle=p.col;
    ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2); ctx.fill();
    ctx.restore();
  });
}

const T_STAGGER=300, T_INTRO=200+ITEMS.length*T_STAGGER+600, T_HOLD_PRE=1000;
const T_WALK=650, T_PAUSE=1400, T_SCRATCH=800, T_RELIEF=280, T_SOL_IN=600, T_HOLD_SOL=2200;
const T_PER=T_WALK+T_PAUSE+T_SCRATCH+T_RELIEF+T_SOL_IN+T_HOLD_SOL;
const T_ITEMS_START=T_INTRO+T_HOLD_PRE;
const T_ALL_DONE=T_ITEMS_START+ITEMS.length*T_PER;
const T_BRAND_START=T_ALL_DONE+800;
const T_BRAND_DUR=7500;
const T_CTA=T_BRAND_START+3200;
const T_TOTAL=T_BRAND_START+T_BRAND_DUR;

function iTime(i){
  const base=T_ITEMS_START+i*T_PER;
  return {
    base, walkEnd:base+T_WALK, pauseEnd:base+T_WALK+T_PAUSE,
    scrEnd:base+T_WALK+T_PAUSE+T_SCRATCH,
    relEnd:base+T_WALK+T_PAUSE+T_SCRATCH+T_RELIEF,
    solEnd:base+T_WALK+T_PAUSE+T_SCRATCH+T_RELIEF+T_SOL_IN,
    cycleEnd:base+T_PER,
  };
}

function L(){
  var s=W/1100;
  const probFsize=Math.max(17,Math.round(26*s));
  const solFsize=Math.max(15,Math.round(23*s));
  const subFsize=Math.max(11,Math.round(14*s));
  const hFsize=Math.max(13,Math.round(15*s));
  const figSize=Math.max(32,Math.round(H*0.076));
  const rowH=H*0.130;
  const rowTop=H*0.205;
  const rowYs=ITEMS.map((_,i)=>rowTop+i*rowH);
  const figX=W*0.062;
  const probX=W*0.112;
  const divX=W*0.495;
  const solX=W*0.522;
  return {probFsize,solFsize,subFsize,hFsize,figSize,rowH,rowYs,figX,probX,divX,solX};
}

let tws=null;

function drawPaper(lo){
  ctx.fillStyle=BG; ctx.fillRect(0,0,W,H);
  ctx.strokeStyle="rgba(0,80,100,0.052)"; ctx.lineWidth=0.7;
  lo.rowYs.forEach(y=>{
    ctx.beginPath(); ctx.moveTo(W*0.022,y+lo.rowH*0.62);
    ctx.lineTo(W*0.978,y+lo.rowH*0.62); ctx.stroke();
  });
  ctx.strokeStyle="rgba(200,90,80,0.15)"; ctx.lineWidth=1.1;
  ctx.beginPath(); ctx.moveTo(W*0.096,H*0.08); ctx.lineTo(W*0.096,H*0.93); ctx.stroke();
}

function drawHeaders(elapsed,lo){
  const a=clamp((elapsed-500)/600,0,1); if(a<=0) return;
  ctx.save(); ctx.globalAlpha=a;
  ctx.font="700 "+lo.hFsize+"px \"Space Mono\",monospace";
  ctx.textBaseline="middle";
  ctx.fillStyle="rgba(175,50,42,0.65)"; ctx.textAlign="left";
  ctx.fillText("WHAT'S BROKEN",lo.probX,lo.rowYs[0]-H*0.090);
  ctx.fillStyle="rgba(0,95,100,0.70)"; ctx.textAlign="left";
  ctx.fillText("THE TELEDIRECTMD WAY",lo.solX,lo.rowYs[0]-H*0.090);
  ctx.lineWidth=0.9;
  ctx.strokeStyle="rgba(175,50,42,0.22)";
  const w1=ctx.measureText("WHAT'S BROKEN").width;
  ctx.beginPath(); ctx.moveTo(lo.probX,lo.rowYs[0]-H*0.063);
  ctx.lineTo(lo.probX+w1,lo.rowYs[0]-H*0.063); ctx.stroke();
  ctx.strokeStyle="rgba(0,95,100,0.22)";
  const w2=ctx.measureText("THE TELEDIRECTMD WAY").width;
  ctx.beginPath(); ctx.moveTo(lo.solX,lo.rowYs[0]-H*0.063);
  ctx.lineTo(lo.solX+w2,lo.rowYs[0]-H*0.063); ctx.stroke();
  ctx.strokeStyle="rgba(0,80,90,0.09)"; ctx.lineWidth=0.8; ctx.setLineDash([4,9]);
  ctx.beginPath(); ctx.moveTo(lo.divX,lo.rowYs[0]-H*0.080);
  ctx.lineTo(lo.divX,lo.rowYs[4]+H*0.072); ctx.stroke();
  ctx.setLineDash([]); ctx.restore();
}

function drawRow(i,elapsed,lo){
  const item=ITEMS[i], TT=iTime(i);
  const dropA=clamp((elapsed-(200+i*T_STAGGER))/380,0,1);
  if(dropA<=0) return;
  const dropY=(1-easeOut(dropA))*H*0.026;
  const y=lo.rowYs[i]+dropY;

  ctx.save(); ctx.globalAlpha=dropA*0.35;
  ctx.font="700 "+Math.max(9,Math.round(W*0.010))+"px \"Space Mono\",monospace";
  ctx.fillStyle=RED; ctx.textAlign="center"; ctx.textBaseline="middle";
  ctx.fillText(i+1,lo.probX-W*0.022,y); ctx.restore();

  const wasScratched=elapsed>=TT.scrEnd;
  const scrP=clamp((elapsed-TT.pauseEnd)/T_SCRATCH,0,1);
  const dimA=wasScratched?1:(scrP>0.38?clamp((scrP-0.38)/0.45,0,1)*0.52:0);
  const approach=elapsed>=TT.base&&elapsed<TT.pauseEnd?clamp((elapsed-TT.base)/T_WALK,0,1)*0.40:0;
  ctx.save(); ctx.globalAlpha=dropA*lerp(1,0.22,dimA);
  ctx.font="700 "+lo.probFsize+"px \"Caveat\",cursive";
  ctx.textAlign="left"; ctx.textBaseline="middle";
  const rc=lerp(28,145,approach)|0, gc=lerp(18,32,approach)|0, bc=lerp(8,22,approach)|0;
  ctx.fillStyle="rgb("+rc+","+gc+","+bc+")";
  ctx.fillText(item.prob,lo.probX,y); ctx.restore();

  if(scrP>0&&scratchPaths[i]){
    scratchPaths[i].forEach(function(stroke,si){
      var delay=si*0.26;
      var sp=clamp((scrP-delay)/(1-delay*0.5),0,1); if(sp<=0) return;
      var pts=stroke.pts, show=sp*(pts.length-1), showInt=Math.floor(show);
      ctx.save(); ctx.globalAlpha=dropA*clamp(sp*3,0,1);
      ctx.strokeStyle=RED; ctx.lineWidth=stroke.w*(W/1100);
      ctx.lineCap="round"; ctx.lineJoin="round";
      ctx.beginPath(); ctx.moveTo(pts[0].x,pts[0].y);
      for(var k=1;k<=showInt&&k<pts.length;k++) ctx.lineTo(pts[k].x,pts[k].y);
      if(showInt<pts.length-1){
        var f=show-showInt;
        ctx.lineTo(lerp(pts[showInt].x,pts[showInt+1].x,f),lerp(pts[showInt].y,pts[showInt+1].y,f));
      }
      ctx.stroke(); ctx.restore();
    });
  }

  var solP=clamp((elapsed-TT.relEnd)/T_SOL_IN,0,1);
  if(solP>0){
    var sl=(1-easeOut(clamp(solP*2.5,0,1)))*W*0.032;
    var sa=easeOut(clamp(solP*2.2,0,1));
    var scl=lerp(0.88,1,easeOut(clamp(solP*3,0,1)));
    ctx.save(); ctx.globalAlpha=sa*dropA;
    var cR=Math.max(11,lo.solFsize*0.54);
    ctx.save(); ctx.translate(lo.solX+cR*0.9+sl,y); ctx.scale(scl,scl);
    ctx.fillStyle=TEAL_L;
    ctx.beginPath(); ctx.arc(0,0,cR,0,Math.PI*2); ctx.fill();
    ctx.strokeStyle="rgba(255,255,255,0.95)"; ctx.lineWidth=Math.max(1.8,W*0.002);
    ctx.lineCap="round"; ctx.lineJoin="round";
    var ck=clamp((solP-0.08)/0.42,0,1);
    if(ck>0){
      var r=cR*0.50; ctx.beginPath(); ctx.moveTo(-r*0.55,0);
      if(ck<0.5){ ctx.lineTo(lerp(-r*0.55,-r*0.08,ck/0.5),lerp(0,r*0.55,ck/0.5)); }
      else { ctx.lineTo(-r*0.08,r*0.55); ctx.lineTo(lerp(-r*0.08,r*0.62,(ck-0.5)/0.5),lerp(r*0.55,-r*0.60,(ck-0.5)/0.5)); }
      ctx.stroke();
    }
    ctx.restore();
    var glowF=clamp(1-solP*0.7,0,1);
    ctx.font="700 "+lo.solFsize+"px \"Karla\",sans-serif";
    ctx.shadowColor="rgba(0,130,135,"+(glowF*0.6)+")"; ctx.shadowBlur=glowF*14;
    ctx.fillStyle=NAVY; ctx.textAlign="left"; ctx.textBaseline="middle";
    ctx.fillText(item.sol,lo.solX+cR*2.1+sl,y); ctx.shadowBlur=0;
    if(solP>0.50){
      var subA=clamp((solP-0.50)/0.38,0,1);
      ctx.globalAlpha=sa*dropA*subA*0.62;
      ctx.font="400 "+lo.subFsize+"px \"Karla\",sans-serif";
      ctx.fillStyle=TEAL; ctx.textAlign="left"; ctx.textBaseline="middle";
      ctx.fillText(item.sub,lo.solX+cR*2.1+sl,y+lo.solFsize*1.18);
    }
    ctx.restore();
  }
}

var figSmoothY=null;
function _arm(root,ang,len){ ctx.beginPath(); ctx.moveTo(root.x,root.y); ctx.lineTo(root.x+Math.cos(ang)*len,root.y+Math.sin(ang)*len); ctx.stroke(); }
function _leg(ox,oy,ang,len){ ctx.beginPath(); ctx.moveTo(ox,oy); ctx.lineTo(ox+Math.cos(ang)*len,oy+Math.sin(ang)*len); ctx.stroke(); }
function drawHead(fx,headY,headR,tilt,expressions){
  ctx.fillStyle=BG; ctx.beginPath(); ctx.arc(fx,headY,headR,0,Math.PI*2); ctx.fill();
  ctx.save(); ctx.translate(fx,headY); ctx.rotate(tilt||0);
  ctx.beginPath(); ctx.arc(0,0,headR,0,Math.PI*2); ctx.stroke();
  if(expressions){ expressions(); }
  ctx.restore();
}

function drawFigure(elapsed,lo){
  if(elapsed<T_ITEMS_START-200||elapsed>=T_BRAND_START-100) return;
  var activeRow=-1, state="idle", stateP=0;
  for(var i=0;i<ITEMS.length;i++){
    var TT=iTime(i);
    if(elapsed>=TT.base&&elapsed<TT.cycleEnd){
      activeRow=i;
      if(elapsed<TT.walkEnd)       {state="arrive";   stateP=clamp((elapsed-TT.base)/T_WALK,0,1);}
      else if(elapsed<TT.pauseEnd) {state="read";     stateP=clamp((elapsed-TT.walkEnd)/T_PAUSE,0,1);}
      else if(elapsed<TT.scrEnd)   {state="scratch";  stateP=clamp((elapsed-TT.pauseEnd)/T_SCRATCH,0,1);}
      else if(elapsed<TT.relEnd)   {state="done";     stateP=clamp((elapsed-TT.scrEnd)/T_RELIEF,0,1);}
      else                         {state="celebrate";stateP=clamp((elapsed-TT.relEnd)/(T_SOL_IN+T_HOLD_SOL*0.4),0,1);}
      break;
    }
  }
  var afterAll=iTime(ITEMS.length-1).cycleEnd;
  if(activeRow===-1&&elapsed>=afterAll){state="exit";stateP=clamp((elapsed-afterAll)/500,0,1);activeRow=ITEMS.length-1;}
  if(activeRow<0) return;

  var targetY=lo.rowYs[Math.min(activeRow,ITEMS.length-1)];
  if(figSmoothY===null) figSmoothY=targetY;
  figSmoothY+=(targetY-figSmoothY)*0.090;

  var s=lo.figSize;
  var headR=s*0.28, bodyL=s*0.40, armL=s*0.34, legL=s*0.38;
  var fx=lo.figX;
  if(activeRow===0&&state==="arrive") fx=lerp(-s,lo.figX,easeOut(stateP));
  if(state==="exit") fx=lerp(lo.figX,-s*1.5,easeOut2(stateP));
  var y=figSmoothY;
  var shY=y-bodyL*0.5, hipY=y+bodyL*0.5, headY=shY-headR-s*0.04;
  var aRoot={x:fx, y:shY+s*0.05};

  ctx.save();
  ctx.strokeStyle=NAVY; ctx.lineCap="round"; ctx.lineJoin="round";
  ctx.lineWidth=Math.max(2.2,s*0.070);
  ctx.beginPath(); ctx.moveTo(fx,shY); ctx.lineTo(fx,hipY); ctx.stroke();

  if(state==="arrive"){
    var sw=Math.sin(stateP*Math.PI*5)*0.40;
    _arm(aRoot,Math.PI/2+0.44+sw,armL); _arm(aRoot,Math.PI/2-0.44-sw,armL);
    _leg(fx,hipY,Math.PI/2+0.20+sw,legL); _leg(fx,hipY,Math.PI/2-0.20-sw,legL);
    drawHead(fx,headY,headR,0,null);
  } else if(state==="read"){
    var ponder=easeOut(stateP);
    _arm(aRoot,lerp(Math.PI/2-0.38,0.384,ponder),armL*0.92);
    _arm(aRoot,Math.PI/2+0.44,armL);
    _leg(fx,hipY,Math.PI/2+0.13,legL); _leg(fx,hipY,Math.PI/2-0.13,legL);
    drawHead(fx,headY,headR,0.10*ponder,null);
  } else if(state==="scratch"){
    var sw2=Math.sin(stateP*Math.PI*3.5)*0.22;
    var baseAng=0.384+sw2;
    var armEndX=aRoot.x+Math.cos(baseAng)*armL*1.18;
    var armEndY=aRoot.y+Math.sin(baseAng)*armL*1.18;
    ctx.beginPath(); ctx.moveTo(aRoot.x,aRoot.y); ctx.lineTo(armEndX,armEndY); ctx.stroke();
    _arm(aRoot,Math.PI/2+0.45,armL*0.82);
    _leg(fx,hipY,Math.PI/2+0.10,legL); _leg(fx,hipY,Math.PI/2-0.10,legL);
    drawHead(fx,headY,headR,0,null);
    ctx.save(); ctx.fillStyle=RED; ctx.shadowColor="rgba(200,40,30,0.5)"; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.arc(armEndX,armEndY,s*0.065,0,Math.PI*2); ctx.fill();
    ctx.shadowBlur=0;
    if(stateP>0.08){
      ctx.globalAlpha=0.50;
      for(var k=0;k<3;k++){
        var ang2=Math.random()*Math.PI*2, dist2=2+Math.random()*5;
        ctx.fillStyle=RED; ctx.beginPath(); ctx.arc(armEndX+Math.cos(ang2)*dist2,armEndY+Math.sin(ang2)*dist2,1.0,0,Math.PI*2); ctx.fill();
      }
    }
    ctx.restore();
  } else if(state==="done"){
    _arm(aRoot,Math.PI/2+0.44,armL); _arm(aRoot,Math.PI/2-0.38,armL);
    _leg(fx,hipY,Math.PI/2+0.13,legL); _leg(fx,hipY,Math.PI/2-0.13,legL);
    drawHead(fx,headY,headR,0,null);
  } else if(state==="celebrate"){
    var liftP=spring(clamp(stateP*1.8,0,1));
    var jumpOff=Math.sin(stateP*Math.PI)*s*0.09;
    _arm(aRoot,lerp(Math.PI/2+0.44,-Math.PI/2-0.45,liftP),armL);
    _arm(aRoot,lerp(Math.PI/2-0.38,-Math.PI/2+0.45,liftP),armL);
    _leg(fx,hipY,Math.PI/2+0.20,legL); _leg(fx,hipY,Math.PI/2-0.20,legL);
    ctx.save(); ctx.translate(0,-jumpOff);
    drawHead(fx,headY,headR,0,function(){
      ctx.strokeStyle=INK; ctx.lineWidth=Math.max(1.6,s*0.050);
      ctx.beginPath(); ctx.arc(0,headR*0.10,headR*0.40,0.22,Math.PI-0.22); ctx.stroke();
      ctx.fillStyle=INK;
      ctx.beginPath(); ctx.arc(-headR*0.30,-headR*0.10,headR*0.13,0,Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(headR*0.30,-headR*0.10,headR*0.13,0,Math.PI*2); ctx.fill();
    });
    ctx.restore();
  } else {
    _arm(aRoot,Math.PI/2+0.44,armL); _arm(aRoot,Math.PI/2-0.38,armL);
    _leg(fx,hipY,Math.PI/2+0.14,legL); _leg(fx,hipY,Math.PI/2-0.14,legL);
    drawHead(fx,headY,headR,0,null);
  }
  ctx.restore();
}

function drawBrand(elapsed){
  var age=elapsed-T_BRAND_START; if(age<=0) return;
  ctx.fillStyle="rgba(244,239,232,"+clamp(age/700,0,0.96)+")";
  ctx.fillRect(0,0,W,H);
  if(age<200) return;
  if(age>280){
    var ca=clamp((age-280)/500,0,1);
    ctx.save(); ctx.globalAlpha=ca; ctx.fillStyle=CREAM;
    ctx.shadowColor="rgba(0,50,60,0.08)"; ctx.shadowBlur=40;
    _rr(W*0.08,H*0.05,W*0.84,H*0.90,18); ctx.fill();
    ctx.shadowBlur=0; ctx.restore();
  }
  var LOGO_TOP=H*0.09, LINE1_Y=H*0.56, LINE2_Y=H*0.67, BADGE_Y=H*0.80, LINE_Y=H*0.48;
  var LW=Math.min(W*0.40,380), LH=LW*(320/800);
  var lx=W/2-LW/2;
  if(logoImg.complete&&logoImg.naturalWidth>0&&age>400){
    var la=clamp((age-400)/600,0,1),lr=(1-easeOut(clamp((age-400)/500,0,1)))*H*0.03;
    ctx.save(); ctx.globalAlpha=la;
    ctx.drawImage(logoImg,lx,LOGO_TOP+lr,LW,LH);
    ctx.restore();
  }
  if(age>1000){
    var ua=clamp((age-1000)/400,0,1),uw=easeOut(ua)*LW*0.85;
    ctx.save(); ctx.globalAlpha=ua; ctx.strokeStyle=ORANGE;
    ctx.lineWidth=Math.max(2,W*0.002);
    ctx.beginPath();
    ctx.moveTo(W/2-uw/2,LINE_Y); ctx.lineTo(W/2+uw/2,LINE_Y);
    ctx.stroke(); ctx.restore();
  }
  if(age>1600){
    var ta=clamp((age-1600)/500,0,1),tr=(1-easeOut(clamp((age-1600)/420,0,1)))*H*0.025;
    ctx.save(); ctx.globalAlpha=ta;
    ctx.font="700 "+Math.max(30,Math.round(W*0.038))+"px \"Karla\",sans-serif";
    ctx.fillStyle="rgba(0,62,82,0.96)";
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText("A doctor you can reach,",W/2,LINE1_Y+tr);
    ctx.fillText("without leaving home.",W/2,LINE2_Y+tr);
    ctx.restore();
  }
  if(age>2400){
    var ba=clamp((age-2400)/550,0,1),br=(1-easeOut(clamp((age-2400)/460,0,1)))*H*0.015;
    var bf=Math.max(12,Math.round(W*0.014));
    var by=BADGE_Y+br;
    ctx.save(); ctx.globalAlpha=ba; ctx.font="600 "+bf+"px \"Karla\",sans-serif";
    var labels=["$49 Flat Fee","No Insurance","Board-Certified MD","40+ States"];
    var colors=[ORANGE,TEAL,TEAL,NAVY];
    var pad=W*0.022; var total=0;
    var ws=labels.map(function(l){var w=ctx.measureText(l).width+pad;total+=w+W*0.012;return w;});
    total-=W*0.012;
    var sc=total>W*0.72?W*0.72/total:1;
    var tx=W/2-total*sc/2; var ph=bf+W*0.012;
    labels.forEach(function(l,i){
      var lw=ws[i]*sc,p2=pad*sc*0.5;
      ctx.fillStyle=colors[i]; _rr(tx,by,lw,ph,ph/2); ctx.fill();
      ctx.fillStyle="rgba(255,255,255,0.95)";
      ctx.textAlign="left"; ctx.textBaseline="middle";
      ctx.save(); ctx.scale(sc,1); ctx.fillText(l,(tx+p2)/sc,by+ph/2); ctx.restore();
      tx+=lw+W*0.012*sc;
    });
    ctx.restore();
  }
}
function animateCTA(elapsed){
  if(elapsed<T_CTA) return;
  if(!ctaShown){
    ctaShown=true;
    ctaBtn.style.display="block";
    ctaBtn.style.transition="opacity 0.7s ease, transform 0.7s cubic-bezier(0.34,1.56,0.64,1)";
    requestAnimationFrame(function(){requestAnimationFrame(function(){
      ctaBtn.style.opacity="1";
      ctaBtn.style.transform="translateX(-50%) scale(1)";
    });});
  }
}

var popFired=new Array(ITEMS.length).fill(false);

var t0=null, rafId=null, lastTs=null;
function frame(ts){
  if(!t0){t0=ts;lastTs=ts;}
  var elapsed=ts-t0, dt=Math.min(ts-lastTs,50); lastTs=ts;
  var lo=L();
  if(!tws){
    ctx.font="700 "+lo.probFsize+"px \"Caveat\",cursive";
    tws=ITEMS.map(function(item){return ctx.measureText(item.prob).width;});
    scratchPaths=ITEMS.map(function(item,i){
      var x0=lo.probX-lo.probFsize*0.1, x1=lo.probX+tws[i]+lo.probFsize*0.22;
      return buildScratch(lo.rowYs[i],x0,x1,i);
    });
  }
  ITEMS.forEach(function(_,i){
    var TT=iTime(i);
    if(elapsed>=TT.relEnd+80&&!popFired[i]){
      popFired[i]=true;
      var cR=Math.max(11,lo.solFsize*0.54);
      spawnPop(lo.solX+cR*0.9,lo.rowYs[i]);
    }
  });
  tickPops(dt);
  drawPaper(lo);
  drawHeaders(elapsed,lo);
  ITEMS.forEach(function(_,i){drawRow(i,elapsed,lo);});
  drawFigure(elapsed,lo);
  drawPops();
  drawBrand(elapsed);
  animateCTA(elapsed);
  if(elapsed<T_TOTAL){
    rafId=requestAnimationFrame(frame);
  } else {
    document.getElementById("tmd-replay-d").style.display="block";
  }
}

function restart(){
  cancelAnimationFrame(rafId);
  t0=null; lastTs=null; figSmoothY=null; tws=null; scratchPaths=[];
  pops=[]; popFired=new Array(ITEMS.length).fill(false);
  ctaShown=false;
  ctaBtn.style.display="none"; ctaBtn.style.opacity="0";
  ctaBtn.style.transform="translateX(-50%) scale(0.85)";
  document.getElementById("tmd-replay-d").style.display="none";
  rafId=requestAnimationFrame(frame);
}
document.getElementById("tmd-replay-d").addEventListener("click",restart);
ctaBtn.addEventListener("click",function(){ window.location.href="/book-online"; });
rafId=requestAnimationFrame(frame);
})();

// Mobile (<768px)
(function(){
  var wrapEl=document.getElementById('tmd-wrap-m');
  if(!wrapEl||wrapEl.offsetParent===null) return;
  var canvas=document.getElementById('tmd-cm');
  var ctx=canvas.getContext('2d');
  var ctaBtn=document.getElementById('tmd-cta-m');
  var ctaShown=false;

const NAVY="#003E52", TEAL="#006B73", TEAL_L="#007f85", ORANGE="#FF5A36";
const BG="#F4EFE8", INK="#1C1208", RED="#C8291F", CREAM="#FAF7F2";

let W=430, H=720;
function resize(){
  var wrap=document.getElementById("tmd-wrap-m");
  var cssW=wrap.clientWidth;
  var cssH=Math.round(cssW*(720/430));
  var dpr=Math.min(window.devicePixelRatio||1,2);
  canvas.style.width=cssW+"px"; canvas.style.height=cssH+"px";
  canvas.width=cssW*dpr; canvas.height=cssH*dpr;
  ctx.setTransform(dpr,0,0,dpr,0,0);
  W=cssW; H=cssH;
}
resize(); window.addEventListener("resize",resize);

var logoImg=new Image();
logoImg.src=SHARED_LOGO_URI;

function easeOut(t)  { return 1-Math.pow(1-t,3); }
function easeOut2(t) { return 1-(1-t)*(1-t); }
function spring(t)   { return 1+Math.pow(2,-9*t)*Math.sin((t-0.22)*Math.PI*2/0.55)*(-1.12); }
function lerp(a,b,t) { return a+(b-a)*t; }
function clamp(v,a,b){ return Math.max(a,Math.min(b,v)); }
function _rr(x,y,w,h,r){
  ctx.beginPath(); ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y);
  ctx.quadraticCurveTo(x+w,y,x+w,y+r); ctx.lineTo(x+w,y+h-r);
  ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h); ctx.lineTo(x+r,y+h);
  ctx.quadraticCurveTo(x,y+h,x,y+h-r); ctx.lineTo(x,y+r);
  ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath();
}

var ITEMS=[
  { prob:"Insurance runaround",  sol:"No insurance required",   sub:"No prior auth. No denials."    },
  { prob:"Rotating providers",   sol:"Same doctor, every time", sub:"Continuity of care, always"    },
  { prob:"Chatbot medicine",     sol:"Board-certified MD",      sub:"A real doctor. A real answer." },
  { prob:"Long wait times",       sol:"Same-day appointments",   sub:"Book in under 2 minutes"       },
  { prob:"Outrageous bills",     sol:"$49. One price.",         sub:"One payment. Nothing hidden."  },
];

function L(){
  var s=W/430;
  var probFsize = Math.max(18, Math.round(23*s));
  var solFsize  = Math.max(17, Math.round(21*s));
  var subFsize  = Math.max(11, Math.round(13*s));
  var hFsize    = Math.max(10, Math.round(11*s));
  var numFsize  = Math.max(9,  Math.round(9*s));
  var figSize   = Math.max(44, Math.round(H*0.092));
  var rowH      = H * 0.112;
  var rowTop    = H * 0.195;
  var rowYs     = ITEMS.map(function(_,i){return rowTop+i*rowH;});
  var figX      = W * 0.110;
  var textX     = W * 0.220;
  return {probFsize:probFsize,solFsize:solFsize,subFsize:subFsize,hFsize:hFsize,numFsize:numFsize,figSize:figSize,rowH:rowH,rowYs:rowYs,figX:figX,textX:textX};
}

var scratchPaths=[];
function buildScratch(y,x0,x1,seed){
  var strokes=[];
  for(var s=0;s<3;s++){
    var pts=[],n=18;
    var yOff=(s-1)*3.5+Math.sin(seed*7.3+s)*1.8;
    for(var i=0;i<=n;i++){
      var t=i/n;
      var w=Math.sin(seed*13.1+i*2.9+s*5.7)*2.0+Math.cos(seed*8.4+i*4.1)*0.9;
      pts.push({x:x0+t*(x1-x0), y:y+yOff+w});
    }
    strokes.push({pts:pts, w:s===1?3.8:2.1});
  }
  return strokes;
}

var pops=[];
function spawnPop(x,y){
  var cols=[TEAL_L,ORANGE,NAVY,"#00a89a","#FF8A6A","#005f66"];
  for(var i=0;i<9;i++){
    var ang=(Math.PI*2*i/9)+Math.random()*0.45;
    var dist=10+Math.random()*20;
    pops.push({x:x,y:y,tx:x+Math.cos(ang)*dist,ty:y+Math.sin(ang)*dist,
               r:2.0+Math.random()*3.0,alpha:1,col:cols[i%cols.length],age:0});
  }
}
function tickPops(dt){
  pops.forEach(function(p){p.age+=dt/700;p.x=lerp(p.x,p.tx,0.13);p.y=lerp(p.y,p.ty,0.13);
    p.alpha=Math.max(0,1-p.age*1.05);p.r*=0.978;});
  pops=pops.filter(function(p){return p.alpha>0.01;});
}
function drawPops(){
  pops.forEach(function(p){ctx.save();ctx.globalAlpha=p.alpha;ctx.fillStyle=p.col;
    ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill();ctx.restore();});
}

var T_PROB_IN=400, T_STAGGER=280, T_WALK=500, T_PAUSE=1400, T_SCRATCH=800, T_RELIEF=200, T_SOL_IN=550, T_HOLD=1800;
var T_PER=T_WALK+T_PAUSE+T_SCRATCH+T_RELIEF+T_SOL_IN+T_HOLD;
var T_START=700;
var T_ITEMS_START=T_START+ITEMS.length*T_STAGGER+600;
var T_ALL_DONE=T_ITEMS_START+ITEMS.length*T_PER;
var T_BRAND_START=T_ALL_DONE+900;
var T_CTA=T_BRAND_START+3000;
var T_BRAND_DUR=7500;
var T_TOTAL=T_BRAND_START+T_BRAND_DUR;

function ph(){
  var t=0;var probIn=t;t+=T_PROB_IN;var walkEnd=t;t+=T_WALK;var pauseEnd=t;t+=T_PAUSE;var scrEnd=t;t+=T_SCRATCH;var relEnd=t;t+=T_RELIEF;var solEnd=t;t+=T_SOL_IN;
  return {probIn:probIn,walkEnd:walkEnd,pauseEnd:pauseEnd,scrEnd:scrEnd,relEnd:relEnd,solEnd:solEnd};
}
var PH=ph();

var figSmoothY=null;
var popFired=new Array(ITEMS.length).fill(false);
var tws=null;

function drawHead(fx,headY,headR,tilt,expr){
  ctx.fillStyle=BG;ctx.beginPath();ctx.arc(fx,headY,headR,0,Math.PI*2);ctx.fill();
  ctx.save();ctx.translate(fx,headY);ctx.rotate(tilt||0);ctx.beginPath();ctx.arc(0,0,headR,0,Math.PI*2);ctx.stroke();
  if(expr)expr();ctx.restore();
}
function _arm(r,ang,len){ctx.beginPath();ctx.moveTo(r.x,r.y);ctx.lineTo(r.x+Math.cos(ang)*len,r.y+Math.sin(ang)*len);ctx.stroke();}
function _leg(ox,oy,ang,len){ctx.beginPath();ctx.moveTo(ox,oy);ctx.lineTo(ox+Math.cos(ang)*len,oy+Math.sin(ang)*len);ctx.stroke();}

function drawFigure(fx,fy,s,state,sp){
  var headR=s*0.28,bodyL=s*0.42,armL=s*0.36,legL=s*0.40;
  var shY=fy-bodyL*0.5,hipY=fy+bodyL*0.5,headY=shY-headR-s*0.04;
  var ar={x:fx,y:shY+s*0.05};
  ctx.strokeStyle=NAVY;ctx.lineCap="round";ctx.lineJoin="round";ctx.lineWidth=Math.max(2.4,s*0.074);
  ctx.beginPath();ctx.moveTo(fx,shY);ctx.lineTo(fx,hipY);ctx.stroke();
  if(state==="walk"){
    var sw=Math.sin(sp*Math.PI*5)*0.42;
    _arm(ar,Math.PI/2+0.44+sw,armL);_arm(ar,Math.PI/2-0.44-sw,armL);
    _leg(fx,hipY,Math.PI/2+0.22+sw,legL);_leg(fx,hipY,Math.PI/2-0.22-sw,legL);
    drawHead(fx,headY,headR,0,null);
  } else if(state==="read"){
    var p=easeOut(sp);
    _arm(ar,lerp(Math.PI/2-0.36,0.34,p),armL*0.90);_arm(ar,Math.PI/2+0.44,armL);
    _leg(fx,hipY,Math.PI/2+0.13,legL);_leg(fx,hipY,Math.PI/2-0.13,legL);
    drawHead(fx,headY,headR,0.10*p,null);
  } else if(state==="scratch"){
    var sw2=Math.sin(sp*Math.PI*3.5)*0.22;var ang=0.36+sw2;
    var ex=ar.x+Math.cos(ang)*armL*1.20,ey=ar.y+Math.sin(ang)*armL*1.20;
    ctx.beginPath();ctx.moveTo(ar.x,ar.y);ctx.lineTo(ex,ey);ctx.stroke();
    _arm(ar,Math.PI/2+0.45,armL*0.78);_leg(fx,hipY,Math.PI/2+0.10,legL);_leg(fx,hipY,Math.PI/2-0.10,legL);
    drawHead(fx,headY,headR,0,null);
    ctx.save();ctx.fillStyle=RED;ctx.shadowColor="rgba(200,40,30,0.5)";ctx.shadowBlur=7;
    ctx.beginPath();ctx.arc(ex,ey,s*0.068,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;
    if(sp>0.08){ctx.globalAlpha=0.45;for(var k=0;k<3;k++){var a=Math.random()*Math.PI*2,d=2+Math.random()*5;ctx.fillStyle=RED;ctx.beginPath();ctx.arc(ex+Math.cos(a)*d,ey+Math.sin(a)*d,1.1,0,Math.PI*2);ctx.fill();}}
    ctx.restore();
  } else if(state==="celebrate"){
    var liftP=spring(clamp(sp*1.8,0,1));var jumpOff=Math.sin(sp*Math.PI)*s*0.10;
    _arm(ar,lerp(Math.PI/2+0.44,-Math.PI/2-0.48,liftP),armL);_arm(ar,lerp(Math.PI/2-0.38,-Math.PI/2+0.48,liftP),armL);
    _leg(fx,hipY,Math.PI/2+0.20,legL);_leg(fx,hipY,Math.PI/2-0.20,legL);
    ctx.save();ctx.translate(0,-jumpOff);
    drawHead(fx,headY,headR,0,function(){
      ctx.strokeStyle=INK;ctx.lineWidth=Math.max(1.8,s*0.052);
      ctx.beginPath();ctx.arc(0,headR*0.10,headR*0.42,0.22,Math.PI-0.22);ctx.stroke();
      ctx.fillStyle=INK;ctx.beginPath();ctx.arc(-headR*0.30,-headR*0.10,headR*0.14,0,Math.PI*2);ctx.fill();
      ctx.beginPath();ctx.arc(headR*0.30,-headR*0.10,headR*0.14,0,Math.PI*2);ctx.fill();
    });ctx.restore();
  } else {
    _arm(ar,Math.PI/2+0.44,armL);_arm(ar,Math.PI/2-0.38,armL);
    _leg(fx,hipY,Math.PI/2+0.14,legL);_leg(fx,hipY,Math.PI/2-0.14,legL);
    drawHead(fx,headY,headR,0,null);
  }
}

function drawPaper(lo){
  ctx.fillStyle=BG;ctx.fillRect(0,0,W,H);
  ctx.strokeStyle="rgba(0,80,100,0.055)";ctx.lineWidth=0.7;
  lo.rowYs.forEach(function(y){ctx.beginPath();ctx.moveTo(W*0.035,y+lo.rowH*0.70);ctx.lineTo(W*0.965,y+lo.rowH*0.70);ctx.stroke();});
  ctx.strokeStyle="rgba(200,90,80,0.14)";ctx.lineWidth=1.1;
  ctx.beginPath();ctx.moveTo(W*0.185,H*0.07);ctx.lineTo(W*0.185,H*0.94);ctx.stroke();
}

function drawRow(i,elapsed,lo){
  var item=ITEMS[i];
  var dropStart=T_START+i*T_STAGGER;
  var probDropA=clamp((elapsed-dropStart)/T_PROB_IN,0,1);
  if(probDropA<=0)return;
  var itemStart=T_ITEMS_START+i*T_PER;
  var localT=elapsed-itemStart;
  var y=lo.rowYs[i];
  var wasScratched=localT>=PH.scrEnd;
  var scrP=clamp((localT-PH.pauseEnd)/T_SCRATCH,0,1);
  var dimA=wasScratched?1:(scrP>0.25?clamp((scrP-0.25)/0.40,0,1):0);
  var textA=lerp(1,0,dimA);
  var approach=localT>0&&localT<PH.walkEnd?clamp(localT/T_WALK,0,1)*0.38:0;

  var numA=clamp(localT/T_PROB_IN,0,1);
  ctx.save();ctx.globalAlpha=numA*(1-dimA)*0.38;
  ctx.font="700 "+lo.numFsize+"px \"Space Mono\",monospace";
  ctx.fillStyle=RED;ctx.textAlign="center";ctx.textBaseline="middle";
  ctx.fillText(i+1,lo.textX-W*0.038,y);ctx.restore();

  if(probDropA>0.01&&textA>0.01){
    var dropY=(1-easeOut(probDropA))*H*0.022;
    ctx.save();ctx.globalAlpha=probDropA*textA;
    ctx.font="700 "+lo.probFsize+"px \"Caveat\",cursive";
    ctx.textAlign="left";ctx.textBaseline="middle";
    var rc=lerp(28,145,approach)|0,gc=lerp(18,32,approach)|0,bc=lerp(8,22,approach)|0;
    ctx.fillStyle="rgb("+rc+","+gc+","+bc+")";
    ctx.fillText(item.prob,lo.textX,y+dropY);ctx.restore();
  }

  if(scrP>0&&scratchPaths[i]){
    scratchPaths[i].forEach(function(stroke,si){
      var delay=si*0.24;var sp=clamp((scrP-delay)/(1-delay*0.5),0,1);if(sp<=0)return;
      var pts=stroke.pts,show=sp*(pts.length-1),showInt=Math.floor(show);
      var solP2=clamp((localT-PH.relEnd)/T_SOL_IN,0,1);var scrFade=clamp(1-solP2*2.5,0,1);
      if(scrFade<=0.01)return;
      ctx.save();ctx.globalAlpha=clamp(sp*3,0,1)*scrFade;
      ctx.strokeStyle=RED;ctx.lineWidth=stroke.w*(W/430);ctx.lineCap="round";ctx.lineJoin="round";
      ctx.beginPath();ctx.moveTo(pts[0].x,pts[0].y);
      for(var k=1;k<=showInt&&k<pts.length;k++)ctx.lineTo(pts[k].x,pts[k].y);
      if(showInt<pts.length-1){var f=show-showInt;ctx.lineTo(lerp(pts[showInt].x,pts[showInt+1].x,f),lerp(pts[showInt].y,pts[showInt+1].y,f));}
      ctx.stroke();ctx.restore();
    });
  }

  var solP=clamp((localT-PH.relEnd)/T_SOL_IN,0,1);
  if(solP>0){
    if(solP>0.08&&!popFired[i]){popFired[i]=true;var cR2=Math.max(11,lo.solFsize*0.52);spawnPop(lo.textX+cR2*0.9,y);}
    var sl=(1-easeOut(clamp(solP*2.5,0,1)))*W*0.035;var sa=easeOut(clamp(solP*2.2,0,1));
    var scl=lerp(0.86,1,easeOut(clamp(solP*3,0,1)));
    ctx.save();ctx.globalAlpha=sa;var cR=Math.max(11,lo.solFsize*0.52);
    ctx.save();ctx.translate(lo.textX+cR*0.90+sl,y);ctx.scale(scl,scl);
    ctx.fillStyle=TEAL_L;ctx.beginPath();ctx.arc(0,0,cR,0,Math.PI*2);ctx.fill();
    ctx.strokeStyle="rgba(255,255,255,0.95)";ctx.lineWidth=Math.max(2.0,W*0.005);ctx.lineCap="round";ctx.lineJoin="round";
    var ck=clamp((solP-0.06)/0.44,0,1);
    if(ck>0){var r=cR*0.52;ctx.beginPath();ctx.moveTo(-r*0.55,0);
      if(ck<0.5){ctx.lineTo(lerp(-r*0.55,-r*0.08,ck/0.5),lerp(0,r*0.55,ck/0.5));}
      else{ctx.lineTo(-r*0.08,r*0.55);ctx.lineTo(lerp(-r*0.08,r*0.64,(ck-0.5)/0.5),lerp(r*0.55,-r*0.62,(ck-0.5)/0.5));}
      ctx.stroke();}
    ctx.restore();
    var glowF=clamp(1-solP*0.65,0,1);
    ctx.font="700 "+lo.solFsize+"px \"Karla\",sans-serif";
    ctx.shadowColor="rgba(0,130,135,"+(glowF*0.65)+")";ctx.shadowBlur=glowF*14;
    ctx.fillStyle=NAVY;ctx.textAlign="left";ctx.textBaseline="middle";
    ctx.fillText(item.sol,lo.textX+cR*2.0+sl,y);ctx.shadowBlur=0;
    if(solP>0.50){var subA=clamp((solP-0.50)/0.38,0,1);ctx.globalAlpha=sa*subA*0.60;
      ctx.font="400 "+lo.subFsize+"px \"Karla\",sans-serif";ctx.fillStyle=TEAL;ctx.textAlign="left";ctx.textBaseline="middle";
      ctx.fillText(item.sub,lo.textX+cR*2.0+sl,y+lo.solFsize*1.20);}
    ctx.restore();
  }
}

function drawFigureAnimated(elapsed,lo){
  if(elapsed<T_ITEMS_START-200)return;if(elapsed>=T_BRAND_START-100)return;
  var localElapsed=Math.max(0,elapsed-T_ITEMS_START);
  var activeIdx=Math.min(Math.floor(localElapsed/T_PER),ITEMS.length-1);
  var localT=localElapsed-activeIdx*T_PER;var TT=PH;
  var targetY=lo.rowYs[activeIdx];
  if(figSmoothY===null)figSmoothY=targetY;figSmoothY+=(targetY-figSmoothY)*0.085;
  var fx=lo.figX,s=lo.figSize;
  var figX2=fx;
  if(elapsed<T_ITEMS_START+300)figX2=lerp(-s,fx,easeOut(clamp((elapsed-T_ITEMS_START+100)/400,0,1)));
  var state="idle",sp=0;
  if(localT<TT.walkEnd){state="walk";sp=clamp(localT/T_WALK,0,1)*4;}
  else if(localT<TT.pauseEnd){state="read";sp=clamp((localT-TT.walkEnd)/T_PAUSE,0,1);}
  else if(localT<TT.scrEnd){state="scratch";sp=clamp((localT-TT.pauseEnd)/T_SCRATCH,0,1);}
  else if(localT<TT.relEnd){state="done";sp=0;}
  else{var celebDur=T_SOL_IN*0.7;var celebP=clamp((localT-TT.relEnd)/celebDur,0,1);
    if(celebP<1){state="celebrate";sp=celebP;}else{state="idle";sp=0;}}
  ctx.save();drawFigure(figX2,figSmoothY,s,state,sp);ctx.restore();
}

function drawBrand(elapsed){
  var age=elapsed-T_BRAND_START;if(age<=0)return;
  var oa=clamp(age/700,0,0.97);ctx.fillStyle="rgba(244,239,232,"+oa+")";ctx.fillRect(0,0,W,H);
  if(age<200)return;
  if(age>280){var ca=clamp((age-280)/550,0,1);ctx.save();ctx.globalAlpha=ca;ctx.fillStyle=CREAM;
    ctx.shadowColor="rgba(0,50,60,0.10)";ctx.shadowBlur=36;_rr(W*0.07,H*0.12,W*0.86,H*0.64,16);ctx.fill();ctx.shadowBlur=0;ctx.restore();}
  var LW=Math.min(W*0.70,280),LH=LW*(320/800);var lx=W/2-LW/2,ly=H*0.19;
  if(logoImg.complete&&logoImg.naturalWidth>0&&age>380){var la=clamp((age-380)/600,0,1),lr=(1-easeOut(clamp((age-380)/500,0,1)))*H*0.035;
    ctx.save();ctx.globalAlpha=la;ctx.drawImage(logoImg,lx,ly+lr,LW,LH);ctx.restore();}
  if(age>950){var ua=clamp((age-950)/380,0,1),uw=easeOut(ua)*LW*0.84;
    ctx.save();ctx.globalAlpha=ua;ctx.strokeStyle=ORANGE;ctx.lineWidth=2;
    ctx.beginPath();ctx.moveTo(W/2-uw/2,ly+LH+H*0.018);ctx.lineTo(W/2+uw/2,ly+LH+H*0.018);ctx.stroke();ctx.restore();}
  if(age>1500){var ta=clamp((age-1500)/500,0,1),tr2=(1-easeOut(clamp((age-1500)/420,0,1)))*H*0.02;
    ctx.save();ctx.globalAlpha=ta;ctx.font="700 "+Math.max(20,Math.round(W*0.060))+"px \"Karla\",sans-serif";
    ctx.fillStyle="rgba(0,62,82,0.95)";ctx.textAlign="center";ctx.textBaseline="middle";
    ctx.fillText("A doctor you can reach,",W/2,ly+LH+H*0.062+tr2);ctx.fillText("without leaving home.",W/2,ly+LH+H*0.112+tr2);ctx.restore();}
  if(age>2200){var ba=clamp((age-2200)/550,0,1),br=(1-easeOut(clamp((age-2200)/460,0,1)))*H*0.016;
    var bf=Math.max(12,Math.round(W*0.034));var by=ly+LH+H*0.175+br;
    ctx.save();ctx.globalAlpha=ba;ctx.font="600 "+bf+"px \"Karla\",sans-serif";
    var labels=["$49 Flat Fee","No Insurance","40+ States"];var colors=[ORANGE,TEAL,NAVY];
    var pad=W*0.030;var total=0;
    var ws=labels.map(function(l){var w=ctx.measureText(l).width+pad;total+=w+W*0.016;return w;});total-=W*0.016;
    var sc=total>W*0.84?W*0.84/total:1;var tx=W/2-total*sc/2;var ph2=bf+W*0.022;
    labels.forEach(function(l,i){var lw=ws[i]*sc,p2=pad*sc*0.5;ctx.fillStyle=colors[i];_rr(tx,by,lw,ph2,ph2/2);ctx.fill();
      ctx.fillStyle="rgba(255,255,255,0.95)";ctx.textAlign="left";ctx.textBaseline="middle";
      ctx.save();ctx.scale(sc,1);ctx.fillText(l,(tx+p2)/sc,by+ph2/2);ctx.restore();tx+=lw+W*0.016*sc;});
    ctx.restore();}
}

function animateCTA(elapsed){
  if(elapsed<T_CTA||ctaShown)return;ctaShown=true;
  ctaBtn.style.display="block";ctaBtn.style.transition="opacity 0.7s ease, transform 0.7s cubic-bezier(0.34,1.56,0.64,1)";
  requestAnimationFrame(function(){requestAnimationFrame(function(){ctaBtn.style.opacity="1";ctaBtn.style.transform="translateX(-50%) scale(1)";});});
}

var t0=null,rafId=null,lastTs=null;
function frame(ts){
  if(!t0){t0=ts;lastTs=ts;}var elapsed=ts-t0,dt=Math.min(ts-lastTs,50);lastTs=ts;var lo=L();
  if(!tws){ctx.font="700 "+lo.probFsize+"px \"Caveat\",cursive";
    tws=ITEMS.map(function(item){return ctx.measureText(item.prob).width;});
    scratchPaths=ITEMS.map(function(item,i){var x0=lo.textX-lo.probFsize*0.08;var x1=lo.textX+tws[i]+lo.probFsize*0.18;return buildScratch(lo.rowYs[i],x0,x1,i);});}
  tickPops(dt);drawPaper(lo);
  ITEMS.forEach(function(_,i){drawRow(i,elapsed,lo);});
  drawFigureAnimated(elapsed,lo);drawPops();drawBrand(elapsed);animateCTA(elapsed);
  if(elapsed<T_TOTAL){rafId=requestAnimationFrame(frame);}else{document.getElementById("tmd-replay-m").style.display="block";}
}

function restart(){
  cancelAnimationFrame(rafId);t0=null;lastTs=null;figSmoothY=null;tws=null;scratchPaths=[];
  pops=[];popFired=new Array(ITEMS.length).fill(false);ctaShown=false;ctaBtn.style.display="none";ctaBtn.style.opacity="0";
  ctaBtn.style.transform="translateX(-50%) scale(0.85)";document.getElementById("tmd-replay-m").style.display="none";rafId=requestAnimationFrame(frame);
}
document.getElementById("tmd-replay-m").addEventListener("click",restart);
ctaBtn.addEventListener("click",function(){window.location.href="/book-online";});
rafId=requestAnimationFrame(frame);
})();

})();
